object DebugLogger {
    // Use LinkedList for efficient prepending
    private val logEntries = java.util.LinkedList<String>()
    private val dateFormat = SimpleDateFormat("HH:mm:ss.SSS", Locale.US)
    private const val MAX_LOGS = 500

    @Synchronized
    fun log(tag: String, msg: String) {
        val time = dateFormat.format(Date())
        val entry = "[$time] $tag: $msg\n"
        logEntries.addFirst(entry)

        while (logEntries.size > MAX_LOGS) {
            logEntries.removeLast()
        }
        android.util.Log.d("EyecareLog", "$tag: $msg")
    }

    fun logThrowable(tag: String, e: Throwable) {
        val sw = java.io.StringWriter()
        e.printStackTrace(java.io.PrintWriter(sw))
        log(tag, "CRASH DETECTED:\n$sw")
    }

    @Synchronized
    fun getLogs(): String {
        val sb = StringBuilder()
        for (entry in logEntries) {
            sb.append(entry)
        }
        return sb.toString()
    }

    @Synchronized
    fun clear() {
        logEntries.clear()
    }
}

