private fun startTripwire() {
    val i = Intent(applicationContext, LockdownActivity::class.java)
    i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
    i.addFlags(Intent.FLAG_ACTIVITY_NO_ANIMATION)
