private fun updateUsage() {
    val now = System.currentTimeMillis()
    val diff = now - TimeManager.sessionStart
    TimeManager.sessionStart = now
    if (diff > 0 && diff < 10000) {
        TimeManager.continuousUsage += diff
        TimeManager.accumulatedDailyMs += diff
    }
    if (TimeManager.accumulatedDailyMs % 60000 < 2000) TimeManager.save(applicationContext)
}

private fun checkTemporalRules() {
    if (isCriticalAppForeground()) return

    // 1. ELASTIC LEASH: Force lockdown if break is active
    if (TimeManager.isBreakActive() && activePackage != packageName) {
         triggerTemporalLock()
         return
    }

    // 2. THRESHOLD CHECK
    val usage = TimeManager.continuousUsage
    if (TimeManager.accumulatedDailyMs >= TimeManager.DAILY_CAP) {
         triggerTemporalLock("DAILY_LIMIT")
    } else {
         val h = java.util.Calendar.getInstance().get(java.util.Calendar.HOUR_OF_DAY)
         if ((h >= 23 || h < 5) && !TimeManager.isNightPassScheduled) {
             triggerTemporalLock("SLEEP_MODE")
         } else if (usage >= TimeManager.INTERVAL_2_HOUR) {
             TimeManager.breakEndTs = System.currentTimeMillis() + (50 * 60 * 1000L)
             triggerTemporalLock("BREAK")
         } else if (usage >= TimeManager.INTERVAL_60_MIN) {
             TimeManager.breakEndTs = System.currentTimeMillis() + (20 * 60 * 1000L)
             triggerTemporalLock("BREAK")
         } else if (usage >= TimeManager.INTERVAL_30_MIN) {
             TimeManager.breakEndTs = System.currentTimeMillis() + (5 * 60 * 1000L)
             triggerTemporalLock("BREAK")
         }
    }
}

private fun triggerTemporalLock(type: String? = null) {
    val i = Intent(applicationContext, LockdownActivity::class.java)
    val finalType = type ?: if (TimeManager.accumulatedDailyMs >= TimeManager.DAILY_CAP) "DAILY_LIMIT" 
                    else if (java.util.Calendar.getInstance().get(java.util.Calendar.HOUR_OF_DAY) >= 23 || java.util.Calendar.getInstance().get(java.util.Calendar.HOUR_OF_DAY) < 5) "SLEEP_MODE" 
                    else "BREAK"

    i.putExtra("BLOCK_TYPE", finalType)
    i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_REORDER_TO_FRONT or Intent.FLAG_ACTIVITY_NO_ANIMATION)
    startActivity(i)
}

private fun isCriticalAppForeground(): Boolean {
    val safeApps = setOf(
        "com.google.android.apps.maps", "com.waze", 
        "com.google.android.dialer", "com.android.phone", "com.android.server.telecom",
        "com.google.android.deskclock", "com.sec.android.app.clockpackage", "com.android.deskclock"
    )
    val lowerPkg = activePackage.lowercase()
    return safeApps.contains(activePackage) || 
           lowerPkg.contains("dialer") || lowerPkg.contains("call") || 
           lowerPkg.contains("clock") || lowerPkg.contains("alarm")
}

