private fun showShield() {
    if (shieldView != null) return // Already UP
    if (!android.provider.Settings.canDrawOverlays(this)) return

    try {
        val params = WindowManager.LayoutParams(
            WindowManager.LayoutParams.MATCH_PARENT,
            WindowManager.LayoutParams.MATCH_PARENT,
            WindowManager.LayoutParams.TYPE_APPLICATION_OVERLAY,
            // FLAG_NOT_FOCUSABLE = Allow key events to pass behind (like Back btn), 
            // BUT we do NOT set FLAG_NOT_TOUCH_MODAL. This means we CONSUME touches.
            WindowManager.LayoutParams.FLAG_NOT_FOCUSABLE or 
            WindowManager.LayoutParams.FLAG_LAYOUT_IN_SCREEN,
            PixelFormat.TRANSLUCENT
        )
        params.gravity = Gravity.CENTER

        shieldView = FrameLayout(this).apply {
            setBackgroundColor(Color.TRANSPARENT) // Invisible
            // Optional: setBackgroundColor(Color.parseColor("#22FF0000")) // Debug Red Tint
        }

        windowManager?.addView(shieldView, params)
        // DebugLogger.log("SHIELD", "Visual Shield Deployed")

        // AUTO-DISMISS TIMER (2s MAX)
        shieldJob?.cancel()
        shieldJob = scope.launch {
            delay(2000)
            if (guardianState == GuardianState.SCANNING) {
                DebugLogger.log("SHIELD", "Timeout: No anchors found. Dropping shield.")
                hideShield()
                guardianState = GuardianState.IDLE
            }
        }

    } catch (e: Exception) {
        DebugLogger.log("ERROR", "Failed to deploy shield: ${e.message}")
    }
}

