object PermissionTracker {
    private const val PREFS = "perm_tracker_prefs"
    private const val KEY_EVER_ENABLED = "accessibility_ever_enabled"
    private const val KEY_PENALTY_END = "penalty_end_ts"
    private const val KEY_FIX_WINDOW_END = "fix_window_end_ts"

    fun setEverEnabled(ctx: Context) {
        ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE).edit()
            .putBoolean(KEY_EVER_ENABLED, true).apply()
    }

    fun hasBeenEnabled(ctx: Context): Boolean {
        return ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .getBoolean(KEY_EVER_ENABLED, false)
    }

    fun getPenaltyEnd(ctx: Context): Long = 
        ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE).getLong(KEY_PENALTY_END, 0L)

    fun setPenaltyEnd(ctx: Context, ts: Long) {
        ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE).edit()
            .putLong(KEY_PENALTY_END, ts).apply()
    }

    fun getFixWindowEnd(ctx: Context): Long = 
        ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE).getLong(KEY_FIX_WINDOW_END, 0L)

    fun setFixWindowEnd(ctx: Context, ts: Long) {
        ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE).edit()
            .putLong(KEY_FIX_WINDOW_END, ts).apply()
    }

    fun clearFixWindow(ctx: Context) {
        ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE).edit()
            .remove(KEY_FIX_WINDOW_END).apply()
    }
}

