 765 | // Helper: Finds code block ignoring whitespace, tabs, newlines, and quote styles
 766 | function findBlockRobust(originalContent: string, searchBlock: string): { start: number; end: number } | null {
 767 |   if (!searchBlock || !originalContent) return null;
 768 | 
 769 |   const createFingerprint = (str: string) => {
 770 |     let clean = "";
 771 |     const map: number[] = [];
 772 |     for (let i = 0; i < str.length; i++) {
 773 |       if (!/\s/.test(str[i])) {
 774 |         clean += str[i];
 775 |         map.push(i);
 776 |       }
 777 |     }
 778 |     return { clean, map };
 779 |   };
 780 | 
 781 |   const fileFP = createFingerprint(originalContent);
 782 |   const searchFP = createFingerprint(searchBlock);
 783 | 
 784 |   // 1. Strict Structural Match
 785 |   let matchIndex = fileFP.clean.indexOf(searchFP.clean);
 786 | 
 787 |   // 2. Quote-Agnostic Fallback (e.g. " vs ')
 788 |   if (matchIndex === -1) {
 789 |     const normalizeQuotes = (s: string) => s.replace(/['"`]/g, '"');
 790 |     matchIndex = normalizeQuotes(fileFP.clean).indexOf(normalizeQuotes(searchFP.clean));
 791 |   }
 792 | 
 793 |   if (matchIndex === -1) return null;
 794 | 
 795 |   const start = fileFP.map[matchIndex];
 796 |   const end = fileFP.map[matchIndex + searchFP.clean.length - 1] + 1;
 797 |   return { start, end };
 798 | }
 799 | 
 800 | function applyOperation(content: string, op: any) {
 801 |   const lines = content.split("\n");
 802 |   
 803 |   // Helper to find line by trimmed content
 804 |   const getLineIndex = (anchor: string) => {
 805 |       const cleanAnchor = anchor.trim();
 806 |       return lines.findIndex(l => l.trim() === cleanAnchor);
 807 |   };
 808 | 
 809 |   try {
 810 |     // --- AI HEALING ---
 811 |     if (op.is_ai_fix) {
 812 |         if (op.ai_strategy === "range_replace" && op.start_line && op.end_line) {
 813 |             lines.splice(op.start_line - 1, (op.end_line - op.start_line) + 1, op.replace_with || op.content || "");
 814 |                         const shortMsg = op.explanation ? (op.explanation.substring(0, 150) + "...") : "AI Fixed";
 815 |             return { newContent: lines.join("\n"), success: true, score: 95, message: `✨ AI: ${shortMsg}` };
 816 |         }
 817 | 
 818 |         if (op.ai_strategy === "line_insert" && op.anchor_line) {
 819 |             const idx = op.anchor_line - 1;
 820 |             const payload = op.replace_with || op.content || "";
 821 |             if (op.action === "insert_after") {
 822 |                 lines.splice(idx + 1, 0, payload);
 823 |             } else if (op.action === "insert_before") {
 824 |                 lines.splice(idx, 0, payload);
 825 |             } else {
 826 |                 lines[idx] = payload;
 827 |             }
 828 |             const shortMsg = op.explanation ? (op.explanation.substring(0, 150) + "...") : "AI Fixed";
 829 |             return { newContent: lines.join("\n"), success: true, score: 95, message: `✨ AI: ${shortMsg}` };
 830 |         }
 831 |     }
 832 | 
 833 |     switch (op.action) {
 834 |       case "replace_block": {
 835 |         if (!op.find_block) return { newContent: content, success: false, score: 0, message: "Missing find_block" };
 836 |         
 837 |         // Strategy A: Exact Match
 838 |         if (content.includes(op.find_block)) {
 839 |             return { newContent: content.replace(op.find_block, op.replace_with || ""), success: true, score: 100, message: "Exact match" };
 840 |         }
 841 |         // Strategy B: Robust Match (Ignores whitespace/indentation)
 842 |         const match = findBlockRobust(content, op.find_block);
 843 |         if (match) {
 844 |             const before = content.substring(0, match.start);
