492 |         function filterFiles(query) {
493 |             if (!window.repoFiles) return;
494 |             if (!query) return renderFileList(window.repoFiles);
495 |             const scored = window.repoFiles.map(file => {
496 |                 const name = file.path.split('/').pop();
497 |                 const dist = levenshtein(name.toLowerCase(), query.toLowerCase());
498 |                 const maxLen = Math.max(name.length, query.length);
499 |                 const score = Math.round((1 - dist / maxLen) * 100);
500 |                 return { ...file, score: score };
501 |             });
502 |             const filtered = scored.filter(f => f.score > 20).sort((a, b) => b.score - a.score);
503 |             renderFileList(filtered, true);
504 |         }
