ops.replace_with:
let currentModelList = [];
let currentModelTargetKey = null;

async function fetchRemoteModels(key) {
    currentModelTargetKey = key;
    showGlobalToast("Fetching registry...");

    try {
        const res = await fetch(CONFIG.funcUrl, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: apiBody({ action: 'fetch_models', provider_id: key })
        });

        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        const data = await res.json();

        if (data.models && data.models.length > 0) {
            currentModelList = data.models;
            renderModelSelector(data.models);
            document.getElementById('model-selector-overlay').classList.add('active');
            document.getElementById('model-search').value = '';
            document.getElementById('model-search').focus();
        } else {
            throw new Error("No models returned from provider.");
        }
    } catch(e) {
        console.error("Model Fetch Error:", e);
        showGlobalToast("Fetch failed: " + e.message, true);
    }
}

function renderModelSelector(models) {
    const container = document.getElementById('model-selector-list');
    container.innerHTML = models.map(m => `
        <div class="model-item">
            <span class="model-id">${m.id}</span>
            <div class="model-actions">
                <button class="icon-btn" onclick="copyModelId('${m.id}')" title="Copy ID">📋</button>
                <button class="btn btn-primary" style="width:auto; padding:4px 12px; font-size:11px;" 
                    onclick="selectModel('${m.id}')">Select</button>
            </div>
        </div>
    `).join('');
}

function filterModelList(q) {
    const filtered = currentModelList.filter(m => m.id.toLowerCase().includes(q.toLowerCase()));
    renderModelSelector(filtered);
}

function copyModelId(id) {
    navigator.clipboard.writeText(id).then(() => showGlobalToast("ID Copied!"));
}

function selectModel(id) {
    if (!currentModelTargetKey) return;
    updateAIProvider(currentModelTargetKey, 'model', id);
    showGlobalToast(`Selected: ${id}`);
    closeModelSelector();
    renderAIConfigUI(); // Refresh UI to show the new model
}

function closeModelSelector() {
    document.getElementById('model-selector-overlay').classList.remove('active');
    currentModelTargetKey = null;
}

