package com.guardian.net

import android.app.admin.DevicePolicyManager
import android.content.ComponentName
import android.content.Context
import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.provider.Settings
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.compose.foundation.clickable
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.foundation.text.selection.SelectionContainer
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.graphics.vector.ImageVector
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.text.input.PasswordVisualTransformation
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import kotlinx.coroutines.delay

class MainActivity : ComponentActivity() {

    private fun isAccessibilityEnabled(): Boolean {
        val expectedService = "$packageName/com.guardian.net.GuardService"
        val enabledServices = Settings.Secure.getString(contentResolver, Settings.Secure.ENABLED_ACCESSIBILITY_SERVICES)
        return enabledServices?.contains(expectedService) == true
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState) 

        setContent {
            // DARK THEME DASHBOARD
            MaterialTheme(
                colorScheme = darkColorScheme(
                    background = Color(0xFF121212),
                    surface = Color(0xFF1E1E1E),
                    primary = Color(0xFFBB86FC),
                    error = Color(0xFFCF6679),
                    onSurface = Color.White
                )
            ) {
                Scaffold(
                    containerColor = MaterialTheme.colorScheme.background
                ) {
                    DashboardContent(padding = it)
                }
            }

            // PERMISSION WATCHDOG
            LaunchedEffect(Unit) {
                while(true) {
                    val hasOverlay = Settings.canDrawOverlays(this@MainActivity)
                    val hasAccess = isAccessibilityEnabled()
                    val now = System.currentTimeMillis()

                    if (!hasOverlay) {
                        val i = Intent(Settings.ACTION_MANAGE_OVERLAY_PERMISSION)
                        i.data = Uri.parse("package:$packageName")
                        i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                        startActivity(i)
                    } else if (!hasAccess && PermissionTracker.hasBeenEnabled(this@MainActivity)) {
                        // ACCESSIBILITY REVOKED - CHECK PENALTY
                        val penaltyEnd = PermissionTracker.getPenaltyEnd(this@MainActivity)
                        val fixWindowEnd = PermissionTracker.getFixWindowEnd(this@MainActivity)

                        if (penaltyEnd == 0L && fixWindowEnd == 0L) {
                            // START 1 HOUR SHAME
                            PermissionTracker.setPenaltyEnd(this@MainActivity, now + 3600000L)
                        } else if (penaltyEnd > 0 && now < penaltyEnd) {
                            // IN SHAME LOOP
                            val i = Intent(this@MainActivity, LockdownActivity::class.java)
                            i.putExtra("BLOCK_TYPE", "PENALTY_SHAME")
                            i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_SINGLE_TOP)
                            startActivity(i)
                        } else if (penaltyEnd > 0 && now >= penaltyEnd) {
                            // SHAME OVER -> START 15s FIX WINDOW
                            PermissionTracker.setPenaltyEnd(this@MainActivity, 0L)
                            PermissionTracker.setFixWindowEnd(this@MainActivity, now + 15000L)
                        } else if (fixWindowEnd > 0 && now < fixWindowEnd) {
                            // IN FIX WINDOW
                            val i = Intent(this@MainActivity, LockdownActivity::class.java)
                            i.putExtra("BLOCK_TYPE", "PENALTY_FIX")
                            i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_SINGLE_TOP)
                            startActivity(i)
                        } else if (fixWindowEnd > 0 && now >= fixWindowEnd) {
                            // FIX WINDOW EXPIRED -> 15 MIN SHAME LOOP
                            PermissionTracker.setFixWindowEnd(this@MainActivity, 0L)
                            PermissionTracker.setPenaltyEnd(this@MainActivity, now + 900000L)
                        }
                    }
                    delay(1500)
                }
            }
        }
    }

