 637 |         // --- THE MODULE BUNDLER (Recursive) ---
 638 |         // --- THE MODULE BUNDLER (With Multiline Import Support) ---
 639 |   async function bundleAndPreview(index) {
 640 |             if(!CONFIG.funcUrl) return;
 641 | 
 642 |             // 1. Setup Context
 643 |             let entry = (typeof index === 'number') ? dbHistory[index] : null;
 644 |             let sha = entry ? entry.sha : null;
 645 |             let rootPrefix = ''; 
 646 |             if (entry && entry.type === 'Prod') {
 647 |                 const match = entry.title.match(/Deployed\s+(.+)/);
 648 |                 if (match && match[1]) rootPrefix = `${match[1]}/`;
 649 |             }
 650 |             
 651 |             // FIX: We use effectiveRoot for stripping paths to ensure subfolders (DSE/) are flattened
 652 |             const effectiveRoot = rootPrefix || CONFIG.projectPath;
 653 |             const entryFile = effectiveRoot + 'index.html';
 654 |             const iframe = document.getElementById('preview-frame');
 655 |             iframe.srcdoc = `<div style="color:#666; font-family:sans-serif; text-align:center; padding:20px;">Bundling ${entryFile}...</div>`;
 656 | 
 657 |             // 2. Fetch All Files
 658 |             let allFiles = [];
 659 |             try {
 660 |                  const res = await fetch(CONFIG.funcUrl, { method: 'POST', headers: {'Content-Type': 'application/json'}, body: apiBody({ action: 'fetch' }) });
 661 |                  const data = await res.json();
 662 |                  allFiles = data.files.map(f => f.path);
 663 |             } catch(e) { return iframe.srcdoc = "Error fetching file list"; }
 664 | 
 665 |             const fileCache = {}; 
 666 |             const versionFiles = allFiles.filter(f => f.startsWith(effectiveRoot));
 667 | 
 668 |             async function fetchAndCache(path) {
 669 |                 if(fileCache[path]) return;
 670 |                 try {
 671 |                     const res = await fetch(CONFIG.funcUrl, {
 672 |                         method: 'POST', headers: {'Content-Type': 'application/json'},
 673 |                         body: apiBody({ action: 'preview_file', file_path: path, ref_sha: sha })
 674 |                     });
 675 |                     const data = await res.json();
 676 |                     if(data.content) fileCache[path] = { content: b64DecodeUnicode(data.content), mime: getMime(path) };
 677 |                 } catch(e) {}
 678 |             }
 679 |             function getMime(path) {
 680 |                 if(path.endsWith('.html')) return 'text/html';
 681 |                 if(path.endsWith('.js')) return 'text/javascript';
 682 |                 if(path.endsWith('.css')) return 'text/css';
 683 |                 return 'application/octet-stream';
 684 |             }
 685 | 
 686 |             await Promise.all(versionFiles.map(f => fetchAndCache(f)));
 687 |             if(!fileCache[entryFile]) return iframe.srcdoc = `Error: ${entryFile} not found`;
 688 | 
 689 |             // 3. REWRITE IMPORTS (The Linker)
 690 |             function rewriteImports(code, currentPath) {
 691 |                 return code.replace(/(import|export)([\s\S]*?)(['"])([^'"]+)(['"])/g, (match, keyword, mid, q1, importPath, q2) => {
 692 |                     if(importPath.startsWith('.')) {
 693 |                         const resolved = resolvePath(currentPath, importPath);
 694 |                         
 695 |                         // FIX: Use effectiveRoot to strip the prefix (e.g. "DSE/ui.js" -> "ui.js")
 696 |                         const cleanKey = resolved.startsWith(effectiveRoot) ? resolved.substring(effectiveRoot.length) : resolved;
 697 |                         return `${keyword}${mid}${q1}${cleanKey}${q2}`;
 698 |                     }
 699 |                     return match;
 700 |                 });
 701 |             }
 702 | 
 703 |             // Rewrite all cached JS files
 704 |             Object.keys(fileCache).forEach(path => {
 705 |                 if(fileCache[path].mime === 'text/javascript') {
 706 |                     fileCache[path].content = rewriteImports(fileCache[path].content, path);
 707 |                 }
 708 |             });
 709 | 
 710 |             // 4. GENERATE BLOBS & IMPORT MAP
 711 |             const importMap = { imports: {} };
 712 |             Object.keys(fileCache).forEach(path => {
 713 |                 // FIX: Use effectiveRoot to generate flat map keys
 714 |                 const mapKey = path.startsWith(effectiveRoot) ? path.substring(effectiveRoot.length) : path;
 715 |                 const blob = new Blob([fileCache[path].content], { type: fileCache[path].mime });
 716 |                 const blobUrl = URL.createObjectURL(blob);
 717 |                 fileCache[path].blobUrl = blobUrl;
 718 |                 importMap.imports[mapKey] = blobUrl;
 719 |             });
 720 | 
 721 |             // 5. INJECT INTO HTML
 722 |             let html = fileCache[entryFile].content;
 723 |             const parser = new DOMParser();
 724 |             const doc = parser.parseFromString(html, 'text/html');
 725 | 
 726 |             // Fix A: Rewrite Inline Scripts
 727 |             doc.querySelectorAll('script:not([src])').forEach(el => {
 728 |                 if (el.type === 'module' || el.textContent.includes('import')) {
 729 |                     el.textContent = rewriteImports(el.textContent, entryFile);
 730 |                 }
 731 |             });
 732 | 
 733 |             // Fix B: Rewrite External Scripts
 734 |             doc.querySelectorAll('script[src]').forEach(el => {
 735 |                 const src = el.getAttribute('src');
 736 |                 if(!src) return;
 737 |                 // Use effectiveRoot to find the actual file in cache
 738 |                 const repoPath = src.startsWith('./') ? resolvePath(entryFile, src) : (effectiveRoot + src);
 739 |                 
 740 |                 if(fileCache[repoPath]) {
 741 |                     if(fileCache[repoPath].mime === 'text/javascript') {
 742 |                         // FIX: Use effectiveRoot to strip prefix for the inline import
 743 |                         const cleanKey = repoPath.startsWith(effectiveRoot) ? repoPath.substring(effectiveRoot.length) : repoPath;
 744 |                         const inlineScript = doc.createElement('script');
 745 |                         inlineScript.type = 'module';
 746 |                         inlineScript.textContent = `import "${cleanKey}";`;
 747 |                         el.replaceWith(inlineScript);
 748 |                     } else {
 749 |                         el.src = fileCache[repoPath].blobUrl;
 750 |                     }
 751 |                 }
 752 |             });
 753 | 
 754 |             // Fix C: CSS & Images
 755 |             doc.querySelectorAll('link[rel="stylesheet"]').forEach(el => {
 756 |                 const href = el.getAttribute('href');
 757 |                 if(!href) return;
 758 |                 const repoPath = href.startsWith('./') ? resolvePath(entryFile, href) : (effectiveRoot + href);
 759 |                 if(fileCache[repoPath]) el.href = fileCache[repoPath].blobUrl;
 760 |             });
 761 |             doc.querySelectorAll('img[src]').forEach(el => {
 762 |                 const src = el.getAttribute('src');
 763 |                 if(!src) return;
 764 |                 const repoPath = src.startsWith('./') ? resolvePath(entryFile, src) : (effectiveRoot + src);
 765 |                 if(fileCache[repoPath]) el.src = fileCache[repoPath].blobUrl;
 766 |             });
 767 | 
 768 |             // Inject Map
 769 |             const mapTag = doc.createElement('script');
 770 |             mapTag.type = "importmap";
 771 |             mapTag.textContent = JSON.stringify(importMap);
 772 |             doc.head.insertBefore(mapTag, doc.head.firstChild);
 773 | 
 774 |             iframe.srcdoc = doc.documentElement.outerHTML;
 775 |             document.getElementById('preview-url-display').innerText = sha ? `Viewing: ${entry.title}` : `Viewing: Live Dev (${CONFIG.repoName})`;
 776 |             switchTab('tab-preview', document.querySelectorAll('.nav-item')[2]);
 777 |         }
