if (action === "search_repo") {
    const { query, project_path } = payload;
    const tree = await githubFetch(TARGET_REPO, `/git/trees/${DEV_BRANCH}?recursive=1`);
    const files = tree.tree.filter((f: any) => f.type === "blob" && f.path.startsWith(project_path || ""));

    const results: any[] = [];
    // Batch search - processing first 50 files for performance
    for (const file of files.slice(0, 50)) {
        const { content } = await getFileRaw(TARGET_REPO, file.path, DEV_BRANCH);
        if (content) {
            const text = base64ToText(content);
            const lines = text.split('\n');
            lines.forEach((line, i) => {
                if (line.toLowerCase().includes(query.toLowerCase())) {
                    results.push({ 
                        path: file.path, 
                        line: i + 1, 
                        context: line.trim().substring(0, 100)
                    });
                }
            });
        }
    }
    return new Response(JSON.stringify({ results }), { headers: { ...corsHeaders, "Content-Type": "application/json" } });
}

if (action === "fetch_repos") {

// --- GLOBAL SEARCH ---
async function runGlobalSearch() {
    const query = document.getElementById('global-search-input').value.trim();
    if (!query) return;
    const list = document.getElementById('search-results-list');
    list.innerHTML = '<div style="padding:20px; text-align:center; color:var(--ai-accent);">Scanning project...</div>';

    try {
        const res = await fetch(CONFIG.funcUrl, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: apiBody({ action: 'search_repo', query: query, project_path: CONFIG.projectPath })
        });
        const data = await res.json();
        if (!data.results || data.results.length === 0) {
            list.innerHTML = '<div style="padding:20px; text-align:center; color:#666;">No results found.</div>';
            return;
        }
        list.innerHTML = data.results.map(r => `
            <div class="search-result" onclick="openFileViewer('${r.path}')">
                <div style="font-size:12px; font-weight:600;">${r.path} <span style="color:var(--ai-accent)">:${r.line}</span></div>
                <div class="search-context">${escapeHtml(r.context)}</div>
            </div>
        `).join('');
    } catch(e) { list.innerHTML = 'Error: ' + e.message; }
}

// --- STAGING ---
let pendingOps = [];
async function stageChanges() {
    const input = document.getElementById('json-input').value;
    try {
        const payload = smartJSONParse(input);
        pendingOps = Array.isArray(payload) ? payload : (payload.operations || []);
        if (pendingOps.length === 0) return alert("No operations to stage.");

        const list = document.getElementById('staging-list');
        list.innerHTML = '';

        pendingOps.forEach((op, i) => {
            if (op.action === 'comment') return;
            const div = document.createElement('div');
            div.className = 'stage-item';
            div.innerHTML = `
                <div class="stage-header" onclick="previewStageDiff(${i})">
                    <span><b>${op.action.toUpperCase()}</b>: ${op.file_path}</span>
                    <button class="menu-btn" style="color:var(--danger)" onclick="event.stopPropagation(); removeStagedOp(${i})">×</button>
                </div>
            `;
            list.appendChild(div);
        });

        document.getElementById('staging-overlay').classList.add('active');
    } catch(e) { alert("JSON Error: " + e.message); }
}

function removeStagedOp(i) {
    pendingOps.splice(i, 1);
    stageChanges();
}

async function previewStageDiff(i) {
    const op = pendingOps[i];
    const mockId = 'staged-' + i;
    window.OP_CACHE[mockId] = { file: op.file_path, op: op, commit_sha: 'HEAD' };
    openDiffViewer(mockId);
}

// --- RENAME ---
async function openRenameModal(path) {
    const newPath = prompt("Enter new path/name:", path);
    if (!newPath || newPath === path) return;

    showGlobalToast("Preparing Rename...");
    try {
        const res = await fetch(CONFIG.funcUrl, { method: 'POST', headers: {'Content-Type': 'application/json'}, body: apiBody({ action: 'preview_file', file_path: path }) });
        const data = await res.json();

        const ops = [
            { action: 'comment', text: `Rename ${path} to ${newPath}` },
            { action: 'delete_file', file_path: path },
            { action: 'create_file', file_path: newPath, content: b64DecodeUnicode(data.content) }
        ];

        document.getElementById('json-input').value = JSON.stringify(ops, null, 2);
        saveState();
        switchTab('tab-patcher', document.querySelectorAll('.nav-item')[1]);

        if (confirm("Ask AI to heal broken imports in other files?")) {
            toggleChat(true);
            chatHistory.push({ role: 'user', text: `I renamed "${path}" to "${newPath}". Scan the repo and provide a JSON patch to update files that import this path.` });
            processAIResponse();
        }
    } catch(e) { alert("Rename failed: " + e.message); }
}

