  { 
    "action": "replace_block", 
    "file_path": "src/header.ts", 
    "find_block": "export const Header = () => {
  return <h1>Hullo</h1>;
}", 
    "replace_with": "export const Header = () => {
  return <h1>Hello</h1>;
}" 
  },
  { 
    "action": "create_file", 
    "file_path": "src/auth.ts", 
    "content": "export const check = () => true;" 
  }
]
```


