private fun startMonitoring() {
    scope.launch {
        while (isActive) {
            if (DevSettings.isKilled(applicationContext)) {
                stopForeground(STOP_FOREGROUND_REMOVE)
                delay(5000)
                continue
            }

            if (isScreenActive) {
                TimeManager.checkNewDay(applicationContext)
                updateUsage()
                checkTemporalRules()
            }

            if (isCriticalAppForeground()) {
                delay(2000)
                continue
            }

            if (TimeManager.isBreakActive()) {
                val wins = windows
                var exploit = false
                for (w in wins) {
                    val root = w.root ?: continue
                    val p = root.packageName?.toString() ?: ""
                    if (p != packageName && !p.contains("systemui") && !p.contains("dialer") && !p.contains("clock")) {
                        exploit = true; break
                    }
                }
                if (exploit || activePackage != packageName) triggerTemporalLock()
            }

            NukeManager.checkAutoReEnable(applicationContext)
            NukeManager.checkNotifications(applicationContext)

            if (LockManager.isUnlocked(applicationContext)) {
                delay(2000)
                continue
            }

            if (NukeManager.isProtectionDisabled(applicationContext)) {
                delay(5000)
                continue
            }

            if (System.currentTimeMillis() - lastSettingsInteraction < 2000) {
                delay(500)
                continue
            }

            if (!Settings.canDrawOverlays(applicationContext)) {
                val i = Intent(Settings.ACTION_MANAGE_OVERLAY_PERMISSION)
                i.data = Uri.parse("package:$packageName")
                i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                startActivity(i)
            } else if ((Settings.Global.getInt(contentResolver, Settings.Global.AUTO_TIME, 0) != 1 ||
                      Settings.Global.getInt(contentResolver, Settings.Global.AUTO_TIME_ZONE, 0) != 1)) {
                val i = Intent(Settings.ACTION_DATE_SETTINGS)
                i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                startActivity(i)
            } else if (java.util.Locale.getDefault().language != "en") {
                val i = Intent(Settings.ACTION_LOCALE_SETTINGS)
                i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                startActivity(i)
            } else if (!DnsManager.isSecure(applicationContext)) {
                triggerTemporalLock("DNS")
            }

            val now = System.currentTimeMillis()
            if (now - lastCloudSync > 60 * 60 * 1000) {
                lastCloudSync = now
                scope.launch { CloudLogger.syncToCloud(applicationContext) }
            }

            StatsManager.update(applicationContext)
            val pm = getSystemService(android.os.PowerManager::class.java)
            delay(if (pm.isInteractive) 2000 else 10000)
        }
    }
}

