package com.guardian.net

import android.content.Context

object DevSettings {
    private const val PREFS = "dev_prefs"
    private const val KEY_STOPPED = "is_dev_stopped"

    fun isKilled(ctx: Context): Boolean {
        return ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .getBoolean(KEY_STOPPED, false)
    }

    fun setKilled(ctx: Context, killed: Boolean) {
        ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .edit().putBoolean(KEY_STOPPED, killed).apply()
    }
}

