private fun triggerTemporalLock(type: String? = null) {
    val i = Intent(applicationContext, LockdownActivity::class.java)
    // Determine specific break type to avoid "Fix DNS" default
    val finalType = type ?: when {
        TimeManager.accumulatedDailyMs >= TimeManager.DAILY_CAP -> "DAILY_LIMIT"
        System.currentTimeMillis() < TimeManager.manualLockoutEndTs -> "MANUAL_LOCKOUT"
        TimeManager.isBreakActive() -> {
            if (TimeManager.break120Done) "BREAK_50"
            else if (TimeManager.break60Done) "BREAK_20"
            else "BREAK_5"
        }
        (java.util.Calendar.getInstance().get(java.util.Calendar.HOUR_OF_DAY) >= 23 || 
         java.util.Calendar.getInstance().get(java.util.Calendar.HOUR_OF_DAY) < 5) && 
         !TimeManager.isNightPassScheduled -> "SLEEP_MODE"
        !DnsManager.isSecure(applicationContext) -> "DNS"
        else -> "DNS"
    }

    i.putExtra("BLOCK_TYPE", finalType)
    i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_REORDER_TO_FRONT or Intent.FLAG_ACTIVITY_NO_ANIMATION)
    startActivity(i)
}

