object BreakOverlayManager : ViewModelStoreOwner, SavedStateRegistryOwner {
    private var windowManager: WindowManager? = null
    private var composeView: ComposeView? = null
    private var overlayText = mutableStateOf("")
    private var isVisible = false

    override val viewModelStore: ViewModelStore = ViewModelStore()
    private val lifecycleRegistry = LifecycleRegistry(this)
    override val lifecycle: Lifecycle = lifecycleRegistry
    private val savedStateRegistryController = SavedStateRegistryController.create(this)
    override val savedStateRegistry = savedStateRegistryController.savedStateRegistry

    fun show(context: Context, text: String) {
        overlayText.value = text
        if (isVisible) return

        windowManager = context.getSystemService(Context.WINDOW_SERVICE) as WindowManager
        lifecycleRegistry.currentState = Lifecycle.State.RESUMED

        val params = WindowManager.LayoutParams(
            WindowManager.LayoutParams.WRAP_CONTENT,
            WindowManager.LayoutParams.WRAP_CONTENT,
            WindowManager.LayoutParams.TYPE_APPLICATION_OVERLAY,
            WindowManager.LayoutParams.FLAG_NOT_FOCUSABLE or WindowManager.LayoutParams.FLAG_NOT_TOUCH_MODAL,
            PixelFormat.TRANSLUCENT
        ).apply {
            gravity = Gravity.TOP or Gravity.CENTER_HORIZONTAL
            y = 50
        }

        composeView = ComposeView(context).apply {
            setViewTreeLifecycleOwner(this@BreakOverlayManager)
            setViewTreeViewModelStoreOwner(this@BreakOverlayManager)
            setViewTreeSavedStateRegistryOwner(this@BreakOverlayManager)
            setContent {
                val msg by overlayText
                Box(
                    modifier = Modifier
                        .padding(16.dp)
                        .background(Color(0xE6121212), RoundedCornerShape(24.dp))
                        .padding(horizontal = 20.dp, vertical = 10.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Text(
                        text = msg,
                        color = Color(0xFF39CCCC),
                        fontSize = 14.sp,
                        fontWeight = FontWeight.Bold
                    )
                }
            }
        }

        try {
            windowManager?.addView(composeView, params)
            isVisible = true
        } catch (e: Exception) { e.printStackTrace() }
    }

    fun update(text: String) {
        overlayText.value = text
    }

    fun hide() {
        if (!isVisible) return
        try {
            windowManager?.removeView(composeView)
        } catch (e: Exception) { e.printStackTrace() }
        isVisible = false
    }
}

