private fun updateUsage() {
    val now = System.currentTimeMillis()
    val diff = now - TimeManager.sessionStart
    TimeManager.sessionStart = now

    // Don't count usage if the Lockdown screen is showing (Package is US)
    if (activePackage == packageName) return

    if (diff > 0 && diff < 10000) {
        TimeManager.continuousUsage += diff
        TimeManager.accumulatedDailyMs += diff

        // Track Sleep Debt if using Night Pass between 23:00 and 05:00
        val h = java.util.Calendar.getInstance().get(java.util.Calendar.HOUR_OF_DAY)
        if ((h >= 23 || h < 5) && TimeManager.isNightPassScheduled) {
            TimeManager.sleepDebtMs += diff
        }
    }
    if (TimeManager.accumulatedDailyMs % 60000 < 2000) TimeManager.save(applicationContext)
}

ops.replace_with:
private fun updateUsage() {
    val now = System.currentTimeMillis()
    val diff = now - TimeManager.sessionStart
    TimeManager.sessionStart = now

    if (activePackage == packageName) {
        BreakOverlayManager.hide()
        return
    }

    if (diff > 0 && diff < 10000) {
        TimeManager.continuousUsage += diff
        TimeManager.accumulatedDailyMs += diff

        val h = java.util.Calendar.getInstance().get(java.util.Calendar.HOUR_OF_DAY)
        if ((h >= 23 || h < 5) && TimeManager.isNightPassScheduled) {
            TimeManager.sleepDebtMs += diff
        }
        handleBreakWarnings(TimeManager.continuousUsage)
    }
    if (TimeManager.accumulatedDailyMs % 60000 < 2000) TimeManager.save(applicationContext)
}

private fun handleBreakWarnings(usage: Long) {
    val thresholds = listOf(
        Triple(TimeManager.INTERVAL_30_MIN, "5 min", listOf(60000L, 10000L)),
        Triple(TimeManager.INTERVAL_60_MIN, "20 min", listOf(60000L, 10000L)),
        Triple(TimeManager.INTERVAL_2_HOUR, "50 min", listOf(300000L, 60000L, 10000L))
    )

    var showing = false
    for ((limit, type, warns) in thresholds) {
        val remaining = limit - usage
        if (remaining in 1..warns.maxOrNull()!!) {
            val text = if (remaining <= 10000) {
                "Break in ${remaining / 1000}s"
            } else {
                "$type break in ${remaining / 60000}m"
            }
            BreakOverlayManager.show(applicationContext, text)
            BreakOverlayManager.update(text)
            showing = true
            break
        }
    }
    if (!showing) BreakOverlayManager.hide()
}

