private fun handleBreakWarnings(usage: Long) {
    val thresholds = listOf(
        Triple(TimeManager.INTERVAL_30_MIN, "5 min", listOf(60000L, 10000L)),
        Triple(TimeManager.INTERVAL_60_MIN, "20 min", listOf(60000L, 10000L)),
        Triple(TimeManager.INTERVAL_2_HOUR, "50 min", listOf(300000L, 60000L, 10000L))
    )

    var showing = false
    for ((limit, type, warns) in thresholds) {
        val remaining = limit - usage
        if (remaining in 1..warns.maxOrNull()!!) {
            val text = if (remaining <= 10000) {
                "Break in ${remaining / 1000}s"
            } else {
                "$type break in ${remaining / 60000}m"
            }
            BreakOverlayManager.show(applicationContext, text)
            BreakOverlayManager.update(text)
            showing = true
            break
        }
    }
    if (!showing) BreakOverlayManager.hide()
}

