object ShieldOverlayManager {
    private var windowManager: WindowManager? = null
    private var shieldView: FrameLayout? = null
    private var isShieldActive = false
    private var shieldJob: Job? = null
    private val scope = CoroutineScope(Dispatchers.Main)

    fun deploy(ctx: Context) {
        if (isShieldActive) return

        DebugLogger.log("SHIELD", "Deploying Invisible Shield (2s)...")

        windowManager = ctx.getSystemService(Context.WINDOW_SERVICE) as WindowManager
        shieldView = FrameLayout(ctx)
        // Transparent background, consumes touches
        shieldView?.setBackgroundColor(0x00000000) 
        shieldView?.isClickable = true
        shieldView?.isFocusable = true

        val params = WindowManager.LayoutParams(
            WindowManager.LayoutParams.MATCH_PARENT,
            WindowManager.LayoutParams.MATCH_PARENT,
            WindowManager.LayoutParams.TYPE_APPLICATION_OVERLAY,
            // NOT_FOCUSABLE allows nav bar to work, but we catch screen touches
            WindowManager.LayoutParams.FLAG_NOT_FOCUSABLE or 
            WindowManager.LayoutParams.FLAG_WATCH_OUTSIDE_TOUCH,
            PixelFormat.TRANSLUCENT
        ).apply {
            gravity = Gravity.FILL
        }

        try {
            windowManager?.addView(shieldView, params)
            isShieldActive = true
            DebugLogger.log("SHIELD", "Shield Deployed successfully.")

            // Auto-retract after 2 seconds
            shieldJob?.cancel()
            shieldJob = scope.launch {
                delay(2000)
                retract()
            }
        } catch (e: Exception) {
            DebugLogger.log("SHIELD", "Deployment Failed: ${e.message}")
        }
    }

    fun retract() {
        if (!isShieldActive) return
        try {
            if (shieldView != null) {
                windowManager?.removeViewImmediate(shieldView)
                shieldView = null
                isShieldActive = false
                DebugLogger.log("SHIELD", "Shield Retracted.")
            }
        } catch (e: Exception) {
             e.printStackTrace()
        }
    }
}

