import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import androidx.lifecycle.*
import androidx.savedstate.SavedStateRegistry
import androidx.savedstate.SavedStateRegistryController
import androidx.savedstate.SavedStateRegistryOwner
import androidx.savedstate.setViewTreeSavedStateRegistryOwner

object BreakOverlayManager {
    private var windowManager: WindowManager? = null
    private var composeView: ComposeView? = null
    private var lifecycleOwner: OverlayLifecycleOwner? = null
    private var overlayText = mutableStateOf("")
    private var isVisible = false

    fun show(context: Context, text: String) {
        try {
            overlayText.value = text
            if (isVisible) {
                DebugLogger.log("OVERLAY_FLOW", "Overlay already visible, updating text.")
                return
            }

            DebugLogger.log("OVERLAY_FLOW", "Creating Overlay...")

            windowManager = context.getSystemService(Context.WINDOW_SERVICE) as WindowManager

            // 1. Create a fresh LifecycleOwner for this specific view instance
            lifecycleOwner = OverlayLifecycleOwner()
            lifecycleOwner?.onCreate()

            val params = WindowManager.LayoutParams(
                WindowManager.LayoutParams.WRAP_CONTENT,
                WindowManager.LayoutParams.WRAP_CONTENT,
                WindowManager.LayoutParams.TYPE_APPLICATION_OVERLAY,
                WindowManager.LayoutParams.FLAG_NOT_FOCUSABLE or WindowManager.LayoutParams.FLAG_NOT_TOUCH_MODAL,
                PixelFormat.TRANSLUCENT
            ).apply {
                gravity = Gravity.TOP or Gravity.CENTER_HORIZONTAL
                y = 50
            }

            composeView = ComposeView(context).apply {
                // 2. Attach the fresh owners to the view
                setViewTreeLifecycleOwner(lifecycleOwner)
                setViewTreeViewModelStoreOwner(lifecycleOwner)
                setViewTreeSavedStateRegistryOwner(lifecycleOwner)

                setContent {
                    val msg by overlayText
                    Box(
                        modifier = Modifier
                            .padding(16.dp)
                            .background(Color(0xE6121212), RoundedCornerShape(24.dp))
                            .padding(horizontal = 20.dp, vertical = 10.dp),
                        contentAlignment = Alignment.Center
                    ) {
                        Text(
                            text = msg,
                            color = Color(0xFF39CCCC),
                            fontSize = 14.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }
                }
            }

            // 3. Attach View and Start Lifecycle
            windowManager?.addView(composeView, params)
            lifecycleOwner?.onStart()
            lifecycleOwner?.onResume()
            isVisible = true
            DebugLogger.log("OVERLAY_FLOW", "Overlay showed successfully")

        } catch (e: Exception) {
            DebugLogger.log("OVERLAY_ERR", "CRITICAL FAIL: ${e.message}")
            e.printStackTrace()
        }
    }

    fun update(text: String) {
        overlayText.value = text
    }

    fun hide() {
        if (!isVisible) return
        try {
            DebugLogger.log("OVERLAY_FLOW", "Hiding overlay...")
            if (composeView != null) {
                if (composeView!!.parent != null) {
                    windowManager?.removeViewImmediate(composeView)
                }
            }
            // 4. Clean up the lifecycle so it doesn't leak or crash next time
            lifecycleOwner?.onDestroy()
            lifecycleOwner = null
            composeView = null
        } catch (e: Exception) {
            DebugLogger.log("OVERLAY_ERR", "Hide fail: ${e.message}")
        } finally {
            isVisible = false
        }
    }

    // --- HELPER CLASS: Acts as a Fake Activity for the ComposeView ---
    private class OverlayLifecycleOwner : LifecycleOwner, ViewModelStoreOwner, SavedStateRegistryOwner {

        private val lifecycleRegistry = LifecycleRegistry(this)
        private val savedStateRegistryController = SavedStateRegistryController.create(this)
        private val store = ViewModelStore()

        override val lifecycle: Lifecycle get() = lifecycleRegistry
        override val viewModelStore: ViewModelStore get() = store
        override val savedStateRegistry: SavedStateRegistry get() = savedStateRegistryController.savedStateRegistry

        fun onCreate() {
            savedStateRegistryController.performRestore(null)
            lifecycleRegistry.handleLifecycleEvent(Lifecycle.Event.ON_CREATE)
        }

        fun onStart() {
            lifecycleRegistry.handleLifecycleEvent(Lifecycle.Event.ON_START)
        }

        fun onResume() {
            lifecycleRegistry.handleLifecycleEvent(Lifecycle.Event.ON_RESUME)
        }

        fun onDestroy() {
            lifecycleRegistry.handleLifecycleEvent(Lifecycle.Event.ON_PAUSE)
            lifecycleRegistry.handleLifecycleEvent(Lifecycle.Event.ON_STOP)
            lifecycleRegistry.handleLifecycleEvent(Lifecycle.Event.ON_DESTROY)
            store.clear() // Crucial: Clear ViewModels
        }
    }
}

