import kotlin.system.exitProcess

class PanicTileService : TileService() {
    override fun onClick() {
        super.onClick()

        // 1. Reset Lock State
        LockManager.lock(applicationContext)

        // 2. Stop the monitoring service
        val serviceIntent = Intent(this, GuardService::class.java)
        stopService(serviceIntent)

        // 3. Close any active lockdown activities
        val closeIntent = Intent(Intent.ACTION_CLOSE_SYSTEM_DIALOGS)
        sendBroadcast(closeIntent)

        // 4. Force kill the process
        exitProcess(0)
    }

    override fun onStartListening() {
        super.onStartListening()
        tile.state = Tile.STATE_ACTIVE
        tile.updateTile()
    }
}

