import kotlinx.coroutines.* 

object ShieldOverlay {
    private var windowManager: WindowManager? = null
    private var shieldView: View? = null
    private var isVisible = false
    private val scope = CoroutineScope(Dispatchers.Main + Job())

    fun show(context: Context) {
        if (isVisible) return

        windowManager = context.getSystemService(Context.WINDOW_SERVICE) as WindowManager
        shieldView = FrameLayout(context).apply {
            // Lightly visible shield (Soft Blue tint)
            setBackgroundColor(0x224285F4.toInt())
            // Absorb touches
            isClickable = true
            isFocusable = true
        }

        val params = WindowManager.LayoutParams(
            WindowManager.LayoutParams.MATCH_PARENT,
            WindowManager.LayoutParams.MATCH_PARENT,
            WindowManager.LayoutParams.TYPE_ACCESSIBILITY_OVERLAY,
            WindowManager.LayoutParams.FLAG_NOT_FOCUSABLE or 
            WindowManager.LayoutParams.FLAG_LAYOUT_IN_SCREEN,
            PixelFormat.TRANSLUCENT
        )
        params.gravity = Gravity.CENTER

        try {
            windowManager?.addView(shieldView, params)
            isVisible = true
            DebugLogger.log("SHIELD", "Shield Active: Settings Protected.")

            // PROTECTION: Automatically stop absorbing touches after 1.5 seconds
            // This allows the user to use settings, but prevents "Speed Attacks"
            scope.launch {
                delay(1500)
                shieldView?.let {
                    it.setBackgroundColor(0x1100FF00.toInt()) // Turn soft green to show it's now safe
                    val newParams = it.layoutParams as WindowManager.LayoutParams
                    newParams.flags = newParams.flags or WindowManager.LayoutParams.FLAG_NOT_TOUCHABLE
                    windowManager?.updateViewLayout(it, newParams)
                }
            }
        } catch (e: Exception) { e.printStackTrace() }
    }

    fun hide() {
        if (!isVisible) return
        try {
            windowManager?.removeView(shieldView)
            isVisible = false
            shieldView = null
            DebugLogger.log("SHIELD", "Shield Removed.")
        } catch (e: Exception) { e.printStackTrace() }
    }
}

